import java.util.Scanner;

public class AreaPerimetroScan {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

Scanner input = new Scanner(System.in);

System.out.println("Insira a altura do retângulo: ");

double altura = input.nextDouble();

System.out.println("Insira a largura do retângulo: ");

double largura = input.nextDouble();

double area = altura + largura;

double perimetro = (altura + largura)*2;

System.out.println("A área final do retângulo é: "+area);

System.out.println("O perímetro final do retângulo é: "+perimetro);



	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	
	}

}
